SELECT COUNT(*) AS completed_resets
FROM password_reset
WHERE reset_completed = 1 AND reset_completion_date = '2021-02-08';

SELECT user_id
FROM login_history
WHERE ip_address = '192.168.1.100';

SELECT user_id, suspension_reason
FROM accountSuspensions
WHERE suspension_end_date > '2021-02-08';

SELECT COUNT(*) AS active_user_count
FROM users
WHERE is_active = 1;

SELECT COUNT(*) AS two_factor_enabled_count
FROM two_factor_auth
WHERE auth_status = 'enabled';

SELECT username 
FROM users 
ORDER BY username;

SELECT auth_status
FROM two_factor_auth
WHERE user_id = 1;

SELECT COALESCE(username, 'Unknown User') AS username
FROM users
ORDER BY last_login DESC;

SELECT COUNT(*) AS pending_verifications
FROM email_verification
WHERE verification_status = 'pending';

SELECT COUNT(*) AS email_notification_enabled_count
FROM account_settings
WHERE setting_name = 'email_notification' AND setting_value = 'enabled';

SELECT MAX(session_duration)
FROM login_history
WHERE user_id = 1;
